def _parse_sort(sort_str):
    if not sort_str:
        return [("created_at", DESCENDING)]
    parts = [p.strip() for p in sort_str.split(",") if p.strip()]
    sort = []
    for p in parts:
        direction = ASCENDING
        field = p
        if p.startswith("-"):
            direction = DESCENDING
            field = p[1:]
        elif p.startswith("+"):
            field = p[1:]
        if field not in ("created_at", "updated_at", "published_at", "title", "status", "slug"):
            raise BadRequest(f"Invalid sort field: {field}")
        sort.append((field, direction))
    return sort or [("created_at", DESCENDING)]

