@app.route("/documents", methods=["GET"])
def query_documents():
    q = request.args.get("q")
    tag = request.args.get("tag")
    status = request.args.get("status")
    user_id = request.args.get("user_id")
    slug = request.args.get("slug")
    sort_str = request.args.get("sort", "-created_at")
    limit = int(request.args.get("limit", 50))
    skip = int(request.args.get("skip", 0))

    limit = max(1, min(limit, 200))
    skip = max(0, skip)
    sort = _parse_sort(sort_str)

    filt = {}
    if slug:
        filt["slug"] = slug

    if status:
        if status not in ("draft", "published", "archived"):
            raise BadRequest("status must be one of: draft, published, archived")
        filt["status"] = status

    if user_id:
        filt["user_id"] = _oid(user_id, "user_id")

    if tag:
        filt["tags"] = tag

    if q:
        q = q.strip()
        if q:
            filt["$text"] = {"$search": q}

    projection = None
    if q:
        projection = {"score": {"$meta": "textScore"}}
        sort = [("score", {"$meta": "textScore"})] + sort

    cur = documents.find(filt, projection=projection).sort(sort).skip(skip).limit(limit)
    return jsonify([_jsonify_doc(d) for d in cur])

