@app.route("/analytics/documents/by_status", methods=["GET"])
def analytics_documents_by_status():
    pipeline = [
        {"$group": {"_id": "$status", "count": {"$sum": 1}}},
        {"$project": {"_id": 0, "status": "$_id", "count": 1}},
        {"$sort": {"count": -1, "status": 1}},
    ]
    res = list(documents.aggregate(pipeline))
    return jsonify(res)

@app.route("/analytics/tags/top", methods=["GET"])
def analytics_top_tags():
    limit = int(request.args.get("limit", 20))
    limit = max(1, min(limit, 100))
    status = request.args.get("status")

    match = {}
    if status:
        if status not in ("draft", "published", "archived"):
            raise BadRequest("status must be one of: draft, published, archived")
        match["status"] = status

    pipeline = []
    if match:
        pipeline.append({"$match": match})
    pipeline += [
        {"$unwind": {"path": "$tags", "preserveNullAndEmptyArrays": False}},
        {"$group": {"_id": "$tags", "count": {"$sum": 1}}},
        {"$project": {"_id": 0, "tag": "$_id", "count": 1}},
        {"$sort": {"count": -1, "tag": 1}},
        {"$limit": limit},
    ]
    res = list(documents.aggregate(pipeline))
    return jsonify(res)

@app.route("/analytics/authors/top", methods=["GET"])
def analytics_top_authors():
    limit = int(request.args.get("limit", 20))
    limit = max(1, min(limit, 100))
    status = request.args.get("status", "published")
    if status and status not in ("draft", "published", "archived"):
        raise BadRequest("status must be one of: draft, published, archived")

    match = {}
    if status:
        match["status"] = status

    pipeline = []
    if match:
        pipeline.append({"$match": match})
    pipeline += [
        {"$group": {"_id": "$user_id", "count": {"$sum": 1}, "latest": {"$max": "$created_at"}}},
        {"$sort": {"count": -1, "latest": -1}},
        {"$limit": limit},
        {
            "$lookup": {
                "from": "users",
                "localField": "_id",
                "foreignField": "_id",
                "as": "user",
            }
        },
        {"$unwind": {"path": "$user", "preserveNullAndEmptyArrays": True}},
        {
            "$project": {
                "_id": 0,
                "user_id": {"$toString": "$_id"},
                "count": 1,
                "latest": 1,
                "email": "$user.email",
                "username": "$user.username",
                "name": "$user.profile.name",
            }
        },
    ]
    res = list(documents.aggregate(pipeline))
    for r in res:
        if isinstance(r.get("latest"), datetime):
            r["latest"] = r["latest"].isoformat() + "Z"
    return jsonify(res)

@app.route("/analytics/documents/timeline", methods=["GET"])
def analytics_documents_timeline():
    interval = request.args.get("interval", "day")
    status = request.args.get("status", "published")
    if interval not in ("day", "week", "month"):
        raise BadRequest("interval must be one of: day, week, month")
    if status and status not in ("draft", "published", "archived"):
        raise BadRequest("status must be one of: draft, published, archived")

    match = {}
    if status:
        match["status"] = status

    date_field = "$published_at" if status == "published" else "$created_at"

    if interval == "day":
        fmt = "%Y-%m-%d"
    elif interval == "week":
        fmt = "%G-W%V"
    else:
        fmt = "%Y-%m"

    pipeline = []
    if match:
        pipeline.append({"$match": match})
    pipeline += [
        {"$match": {date_field[1:]: {"$ne": None}}},
        {
            "$group": {
                "_id": {
                    "$dateToString": {
                        "format": fmt,
                        "date": date_field,
                    }
                },
                "count": {"$sum": 1},
            }
        },
        {"$project": {"_id": 0, "bucket": "$_id", "count": 1}},
        {"$sort": {"bucket": 1}},
    ]
    res = list(documents.aggregate(pipeline))
    return jsonify(res)

